{
  "grammar": [
    {
      "pattern": "假如 + condition + 的話，就 + result",
      "structure": ["假如", "condition", "的話", "就", "result"],
      "explanation_en": "Use '假如...的話，就...' to express a hypothetical condition and its result, similar to 'if...then...' in English. This structure is common in problem-solving contexts to suggest solutions.",
      "title": "Hypothetical Condition with 假如",
      "meaning": "If (condition), then (result)",
      "when_to_use": ["When proposing a solution to a problem", "When discussing possible scenarios in transactions"],
      "when_not_to_use": ["For factual statements", "For polite requests"],
      "pragmatic_notes": "In Taiwan, '假如' is slightly more formal than '如果', often used in written or careful speech. In daily conversation, '如果' is more common, but '假如' adds a thoughtful tone.",
      "word_order_notes": "The condition clause comes first, followed by '的話' (optional but common), then '就' and the result. The subject can be omitted if clear from context.",
      "english_contrast": "English uses 'if' at the beginning or middle; Chinese always places the condition first.",
      "korean_contrast": "Korean uses '-(으)면' for condition, but Chinese requires the full structure with '假如' and '的話' for clarity.",
      "negative_examples": [
        {
          "text": "假如你故障，就處理。",
          "error": "'故障' is a noun/verb for objects, not for people. Use '假如東西故障' instead."
        }
      ],
      "incorrect_examples": [
        {
          "text": "假如你故障，就處理。",
          "error": "'故障' is used for machines, not people. Correct: '假如東西故障，就處理。'"
        }
      ],
      "transformation_drills": ["Change '如果' to '假如' in a sentence: '如果東西故障，就處理。' -> '假如東西故障，就處理。'"],
      "production_drills": ["Create a sentence using '假如...的話，就...' to suggest a solution for a broken item."],
      "common_error_patterns": ["Using '故障' for people", "Omitting '的話' in formal contexts"],
      "repair_feedback": {
        "word_order": "Place the condition before '就'.",
        "politeness": "Use '假如' for polite suggestions.",
        "vocabulary": "Use '故障' only for objects."
      }
    },
    {
      "pattern": "Subject + 需要 + 幫忙 + 處理 + object",
      "structure": ["Subject", "需要", "幫忙", "處理", "object"],
      "explanation_en": "Use '需要幫忙處理' to express a need for help in handling a problem, common in service or transaction contexts.",
      "title": "Requesting Help with 需要幫忙處理",
      "meaning": "Need help handling (something)",
      "when_to_use": ["When asking for assistance in a store or service", "When reporting a problem like a broken item"],
      "when_not_to_use": ["For simple requests like asking for directions", "For casual favors among friends"],
      "pragmatic_notes": "In Taiwan, '幫忙' is polite and common in customer service. Use '麻煩' for more formal requests.",
      "word_order_notes": "The object comes after '處理'. The subject can be omitted if clear.",
      "english_contrast": "English says 'I need help with...' but Chinese uses '需要幫忙處理' as a fixed phrase.",
      "korean_contrast": "Korean uses '도움이 필요하다' but Chinese specifies the action with '處理'.",
      "negative_examples": [
        {
          "text": "我需要幫忙處理故障。",
          "error": "This is correct, but if the object is a person, use '幫忙' differently."
        }
      ],
      "incorrect_examples": [
        {
          "text": "我需要幫忙處理你。",
          "error": "'處理' is for things, not people. Use '幫忙你' instead."
        }
      ],
      "transformation_drills": ["Change '需要幫忙' to '麻煩' in a sentence: '我需要幫忙處理這個。' -> '麻煩你處理這個。'"],
      "production_drills": ["Ask for help handling a broken phone using '需要幫忙處理'."],
      "common_error_patterns": ["Using '處理' for people", "Omitting '幫忙' in polite requests"],
      "repair_feedback": {
        "word_order": "Place object after '處理'.",
        "politeness": "Add '麻煩' for extra politeness.",
        "vocabulary": "Use '處理' only for objects or situations."
      }
    },
    {
      "pattern": "Subject + 想要 + 取消 + 預約",
      "structure": ["Subject", "想要", "取消", "預約"],
      "explanation_en": "Use '想要取消預約' to express a desire to cancel an appointment, common in service and transaction contexts.",
      "title": "Canceling an Appointment with 想要取消預約",
      "meaning": "Want to cancel an appointment",
      "when_to_use": ["When canceling a reservation or appointment", "When discussing changes in plans"],
      "when_not_to_use": ["For canceling an order (use '退貨')", "For casual cancellations with friends"],
      "pragmatic_notes": "In Taiwan, '取消預約' is standard for appointments. For orders, use '取消訂單'. Always be polite with '不好意思' first.",
      "word_order_notes": "'想要' comes before '取消預約'. The subject can be omitted if clear.",
      "english_contrast": "English says 'I want to cancel my appointment' but Chinese uses '取消預約' as a fixed phrase.",
      "korean_contrast": "Korean uses '예약을 취소하다' but Chinese requires '想要' for desire.",
      "negative_examples": [
        {
          "text": "我想要取消你。",
          "error": "'取消' is for appointments, not people. Use '取消預約' instead."
        }
      ],
      "incorrect_examples": [
        {
          "text": "我想要取消你。",
          "error": "'取消' cannot be used for people. Correct: '我想要取消預約。'"
        }
      ],
      "transformation_drills": ["Change '想要' to '需要' in a sentence: '我想要取消預約。' -> '我需要取消預約。'"],
      "production_drills": ["Create a sentence to cancel a doctor's appointment using '想要取消預約'."],
      "common_error_patterns": ["Using '取消' for people", "Omitting '預約' when referring to appointments"],
      "repair_feedback": {
        "word_order": "Place '取消預約' after '想要'.",
        "politeness": "Start with '不好意思' for politeness.",
        "vocabulary": "Use '取消預約' for appointments, '退貨' for orders."
      }
    }
  ]
}
